tasks.migrate-v5:
deno run --allow-env --allow-net --allow-read - <<'EOF'
import { supabase } from './lib/supabase.ts';
import { readFileSync } from 'node:fs';
const sql = readFileSync('./migrations/v5_layer7_tables.sql', 'utf8');
const { error } = await supabase.rpc('exec_sql', { sql });
if (error) { console.error(error); Deno.exit(1); }
console.log('Migration v5 applied.');
EOF

